MAP_STRING_ADDR = 0x30000008   # null-terminated scenario path string in Xbox RAM
MAP_STRING_MAXLEN = 256

# Active tag map - populated at runtime from MAP_TAG_DATABASE on map detect
_active_tag_map: dict[int, tuple[str, str, str]] = {}
_active_map_name: str = ""

def resolve_map_tags(scenario_path: str) -> bool:
    """Load the tag map for the given scenario path. Returns True if found."""
    global _active_tag_map, _active_map_name
    # Normalise separators
    norm = scenario_path.replace('\\', '/').replace('\\\\', '/').strip('\x00').strip()
    if norm in MAP_TAG_DATABASE:
        _active_tag_map = MAP_TAG_DATABASE[norm]
        _active_map_name = MAP_DISPLAY_NAMES.get(norm, norm.split('/')[-1])
        return True
    # Try backslash variant
    norm2 = norm.replace('/', '\\')
    for key in MAP_TAG_DATABASE:
        if key.replace('/', '\\') == norm2 or key == norm:
            _active_tag_map = MAP_TAG_DATABASE[key]
            _active_map_name = MAP_DISPLAY_NAMES.get(key, key.split('/')[-1])
            return True
    _active_tag_map = {}
    _active_map_name = f"unknown ({norm.split('/')[-1]})"
    return False

def tag_name_from_datum(datum_index: int) -> str:
    """Look up a tag short name from its datum_index using the active map's database."""
    if datum_index is None or datum_index == 0xFFFFFFFF or datum_index == 0:
        return ""
    entry = _active_tag_map.get(datum_index)
    if entry:
        return f"[{entry[0]}] {entry[1]}"
    return ""


